<script setup>
import { computed, ref, watch } from "vue";
import moment from "moment";
import VueDatePicker from "@vuepic/vue-datepicker";
import "@vuepic/vue-datepicker/dist/main.css";
import { useForm } from "@/Components/Form/composables/useForm";
import ErrorMessage from "@/Components/Form/Components/ErrorMessage.vue";
import Help from "@/Components/Other/Help.vue";

const props = defineProps({
    modelValue: {
        type: [String, Object],
        default: "",
    },
    returnObject: {
        type: Boolean,
        default: false,
    },
    returnFormat: {
        type: String,
        default: "YYYY-MM-DD",
    },
    inputFormat: {
        type: String,
        default: "YYYY-MM-DD",
    },
    range: {
        type: Boolean,
        default: false,
    },
    label: [String, Function],
    type: {
        type: String,
        default: "date", // date, time, datetime
    },
    size: {
        type: String,
        default: "default",
    },
    id: String,
    name: String,
    error: String,
    help: String,
});

const emit = defineEmits(["update:modelValue"]);

const { emitFormBlur, emitFormInput, error, inputId, name, required } = useForm(props);

function getDateObject(date) {
    if (!date) {
        return null;
    }

    if (typeof date === "object") {
        return date;
    } else {
        return moment(date, props.inputFormat).toDate(); // Parsování řetězce na objekt Date pomocí moment.js
    }
}

function initObject(obj) {
    if (!props.range) {
        return getDateObject(obj);
    } else {
        let newObj = {
            from: null,
            to: null,
        };

        if (obj) {
            Object.entries(obj).forEach(([key, value]) => {
                newObj[key] = getDateObject(value);
            });

            return newObj;
        } else {
            return newObj;
        }
    }
}

const selectedDate = ref(initObject(props.modelValue));

watch(
    () => props.modelValue,
    (newValue) => {
        selectedDate.value = initObject(newValue);
    },
);

watch(
    () => selectedDate.value,
    (newValue) => {
        if (props.returnObject) {
            emit("update:modelValue", newValue);
        } else {
            let formattedDate = null;

            if (props.range) {
                formattedDate = {
                    from: newValue.from ? moment(newValue.from).format(props.returnFormat) : null,
                    to: newValue.to ? moment(newValue.to).format(props.returnFormat) : null,
                };
            } else {
                formattedDate = moment(newValue).format(props.returnFormat);
            }

            emit("update:modelValue", formattedDate);
        }
    },
    { deep: true },
);

const format = (date) => {
    let format = "DD.MM.YYYY HH:mm:ss";

    if (props.type === "date") {
        format = "DD.MM.YYYY";
    } else if (props.type === "time") {
        format = "HH:mm:ss";
    } else if (props.type === "datetime") {
        format = "DD.MM.YYYY HH:mm:ss";
    }

    return moment(date).format(format);
};
</script>

<template>
    <div>
        <div
            v-if="!props.range"
            class="date-time-wrapper"
            :class="{
                error: error,
            }"
        >
            <label v-if="typeof props.label !== 'undefined'" :for="inputId">
                <component v-if="typeof label === 'function' && label" :is="label" />
                <template v-else>
                    {{ label }}
                </template>
                <span v-if="required" class="required">*</span>
                <Help v-if="help" :help="help" />
            </label>
            <div class="input-wrapper" :class="'size-' + size">
                <VueDatePicker v-model="selectedDate" locale="cs" cancelText="zrušit" selectText="vybrat" :teleport="true" :enable-time-picker="props.type === 'datetime' || props.type === 'time'" :format="format" v-bind:time-picker="props.type === 'time' ? true : null" :uid="inputId" :name="name" />
            </div>
            <ErrorMessage :error="error"></ErrorMessage>
        </div>
        <div
            v-else
            class="date-time-wrapper"
            :class="{
                error: error,
            }"
        >
            <label v-if="typeof props.label !== 'undefined'">
                <component v-if="typeof label === 'function' && label" :is="label" />
                <template v-else>
                    {{ label }}
                </template>
                <span v-if="required" class="required">*</span>
                <Help v-if="help" :help="help" />
            </label>
            <div class="date-range-wrapper">
                <div class="input-wrapper date-from" :class="'size-' + size">
                    <VueDatePicker v-model="selectedDate.from" locale="cs" cancelText="zrušit" selectText="vybrat" :teleport="true" :enable-time-picker="props.type === 'datetime' || props.type === 'time'" :format="format" v-bind:time-picker="props.type === 'time' ? true : null" :uid="inputId + '_from'" :name="name + '_from'" />
                </div>
                <div class="separator">-</div>
                <div class="input-wrapper date-to" :class="'size-' + size">
                    <VueDatePicker v-model="selectedDate.to" locale="cs" cancelText="zrušit" selectText="vybrat" :teleport="true" :enable-time-picker="props.type === 'datetime' || props.type === 'time'" :format="format" v-bind:time-picker="props.type === 'time' ? true : null" :uid="inputId + '_to'" :name="name + '_to'" />
                </div>
            </div>
            <ErrorMessage :error="error"></ErrorMessage>
        </div>
    </div>
</template>

<style scoped>
.separator {
    font-size: 0.923rem;
    font-weight: 500;
    color: var(--color-font-light);
}

.date-time-wrapper {
    .date-range-wrapper {
        display: flex;
        align-items: center;
        gap: 7px;
    }

    .input-wrapper {
        position: relative;
        width: 100%;

        .icon-wrapper {
            position: absolute;
            top: 0;
            bottom: 0;
            left: 0;
            display: flex;
            align-items: center;
            padding-left: 14px;
            pointer-events: none;

            .icon {
                width: 16px;
                height: 16px;
                color: var(--color-font-light);
            }
        }

        input {
            min-height: 40px;
            padding-left: 40px;
            padding-right: 10px;
        }
    }
}

.date-time-wrapper .input-wrapper :deep(input) {
    border-radius: 0.462rem;
    border: 1px solid var(--color-outline);
    background: var(--color-white);
    font-size: 0.923rem;
    color: var(--color-font);
    min-height: 2.308rem;
    height: 2.308rem;

    &:focus {
        border: 1px solid var(--color-outline);
        box-shadow: 0 0 0 1px var(--color-outline);
        outline: none;
    }
}

.error .input-wrapper :deep(input) {
    border-color: var(--color-error);
}

.date-time-wrapper .input-wrapper.size-small :deep(input) {
    min-height: 1.846rem;
}
</style>
